SELECT * 
FROM polling_firms 
WHERE firm_name = 'Firm Name';

SELECT commissioner_name, contact_email
FROM commissioners
WHERE commissioner_id = 1;

SELECT polling_firm, scope
FROM polling_projects
WHERE sample_size = (SELECT MAX(sample_size) FROM polling_projects);

SELECT COUNT(project_id) AS total_projects
FROM polling_projects
WHERE polling_firm = 'Specific Polling Firm';

SELECT polling_projects.project_id, polling_firms.firm_name, polling_projects.fieldwork_start
FROM polling_projects
JOIN polling_firms ON polling_projects.polling_firm = polling_firms.firm_id;

SELECT *, 
       ROW_NUMBER() OVER(ORDER BY sample_size DESC) as ranking
FROM polling_projects;

SELECT firm_name
FROM polling_firms
WHERE firm_id NOT IN (
    SELECT polling_firm
    FROM polling_projects
);

SELECT participation_type
FROM participation_types
WHERE participation_id = 1;

SELECT COUNT(*)
FROM polling_projects
WHERE margin_of_error > 4;
